#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100
#define INF 1000000

int minSum = INF;
int digits[MAX];
int graph[MAX][MAX];
int visited[MAX];

int isDivisible(int* arr, int size) {
    int sum = 0;
    for (int i = 0; i < size; i++) {
        sum += arr[i];
    }
    for (int i = 0; i < size; i++) {
        if (arr[i] != 0 && sum % arr[i] != 0) {
            return 0;
        }
    }
    return 1;
}

void backtrack(int* arr, int size, int current) {
    if (current == size) {
        if (isDivisible(arr, size)) {
            int sum = 0;
            for (int i = 0; i < size; i++) {
                sum += arr[i];
            }
            minSum = (sum < minSum) ? sum : minSum;
        }
        return;
    }
    for (int i = 0; i < size; i++) {
        if (!visited[i] && graph[current][i]) {
            visited[i] = 1;
            arr[size] = digits[i];
            backtrack(arr, size + 1, i);
            visited[i] = 0;
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        for (int i = 0; i < n; i++) {
            scanf("%d", &digits[i]);
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &graph[i][j]);
            }
        }
        minSum = INF;
        int arr[n];
        arr[0] = digits[0];
        visited[0] = 1;
        backtrack(arr, 1, 0);
        if (minSum == INF) {
            printf("-1\n");
        } else {
            printf("%d\n", minSum);
        }
    }
    return 0;
}

