import java.util.Scanner;
public class Main {
    static int minSum = Integer.MAX_VALUE;
    static int[] digits;
    static int[][] graph;
    static boolean[] visited;

    public static boolean isDivisible(int[] arr) {
        int sum = 0;
        for (int i = 0; i < arr.length; i++) {
            sum += arr[i];
        }
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] != 0 && sum % arr[i] != 0) {
                return false;
            }
        }
        return true;
    }

    public static void backtrack(int[] arr, int current) {
        if (current == digits.length) {
            if (isDivisible(arr)) {
                int sum = 0;
                for (int i = 0; i < arr.length; i++) {
                    sum += arr[i];
                }
                minSum = Math.min(sum, minSum);
            }
            return;
        }
        for (int i = 0; i < digits.length; i++) {
            if (!visited[i] && graph[current][i] == 1) {
                visited[i] = true;
                arr[current] = digits[i];
                backtrack(arr, i);
                visited[i] = false;
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            digits = new int[n];
            graph = new int[n][n];
            visited = new boolean[n];
            for (int i = 0; i < n; i++) {
                digits[i] = sc.nextInt();
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    graph[i][j] = sc.nextInt();
                }
            }
            minSum = Integer.MAX_VALUE;
            int[] arr = new int[n];
            arr[0] = digits[0];
            visited[0] = true;
            backtrack(arr, 0);
            if (minSum == Integer.MAX_VALUE) {
                System.out.println(-1);
            } else {
                System.out.println(minSum);
            }
        }
    }
}

